   Errors_Count1                            : Interfaces.Unsigned_16;
   Errors_Count2                            : Interfaces.Unsigned_16;
   Errors_Count3                            : Interfaces.Unsigned_16;
   Errors_Count4                            : Interfaces.Unsigned_16;
